option.value:
:root {
    color-scheme: light;
    --bg: #eef4f8;
    --paper: #ffffff;
    --text: #1f2937;
    --muted: #64748b;
    --line: #dbe4ec;
    --line-strong: #b8c7d6;
    --primary: #0f766e;
    --primary-dark: #115e59;
    --accent: #334155;
    --soft: #f6fafb;
    --soft-accent: #ecfdf5;
    --code-bg: #10202a;
    --code-text: #e7f3f4;
}

* {
    box-sizing: border-box;
}

html {
    background:
        linear-gradient(180deg, rgba(15, 118, 110, 0.08), rgba(51, 65, 85, 0) 300px),
        var(--bg);
}

body {
    max-width: 980px;
    margin: 40px auto;
    padding: 56px 64px;
    background: var(--paper);
    color: var(--text);
    border: 1px solid var(--line);
    border-radius: 8px;
    box-shadow: 0 24px 60px rgba(15, 23, 42, 0.12);
    font-family: "Segoe UI", "Noto Sans JP", "Yu Gothic", "Meiryo", sans-serif;
    font-size: 16px;
    line-height: 1.85;
}

h1,
h2,
h3,
h4 {
    color: var(--accent);
    line-height: 1.35;
    letter-spacing: 0;
}

h1 {
    margin: 0 0 28px;
    padding-bottom: 16px;
    color: #0f172a;
    border-bottom: 4px solid var(--primary);
    font-size: 2.2rem;
}

h1 + p {
    color: var(--muted);
    font-size: 1.05rem;
}

h2 {
    margin-top: 48px;
    margin-bottom: 18px;
    padding: 10px 14px;
    border-left: 6px solid var(--primary);
    background: linear-gradient(90deg, rgba(15, 118, 110, 0.1), rgba(15, 118, 110, 0));
    font-size: 1.55rem;
}

h3 {
    margin-top: 32px;
    margin-bottom: 12px;
    color: var(--primary-dark);
    font-size: 1.22rem;
}

h4 {
    margin-top: 24px;
    margin-bottom: 8px;
    font-size: 1.05rem;
}

p {
    margin: 12px 0;
}

a {
    color: var(--primary-dark);
    text-decoration-thickness: 2px;
    text-underline-offset: 3px;
}

ul,
ol {
    padding-left: 1.5rem;
}

li {
    margin: 6px 0;
}

hr {
    height: 1px;
    margin: 44px 0;
    border: 0;
    background: linear-gradient(90deg, transparent, var(--line-strong), transparent);
}

table {
    width: 100%;
    margin: 22px 0 34px;
    overflow: hidden;
    border-collapse: separate;
    border-spacing: 0;
    border: 1px solid var(--line);
    border-radius: 8px;
    font-size: 0.95rem;
}

th,
td {
    padding: 12px 14px;
    border-right: 1px solid var(--line);
    border-bottom: 1px solid var(--line);
    vertical-align: top;
}

th:last-child,
td:last-child {
    border-right: 0;
}

tr:last-child td {
    border-bottom: 0;
}

th {
    background: var(--accent);
    color: #ffffff;
    font-weight: 700;
    text-align: left;
}

tr:nth-child(even) td {
    background: var(--soft);
}

blockquote {
    margin: 24px 0;
    padding: 16px 20px;
    background: var(--soft-accent);
    border-left: 5px solid var(--primary);
    border-radius: 0 8px 8px 0;
    color: #164e45;
}

code {
    padding: 0.18em 0.42em;
    background: #e8eef3;
    border: 1px solid #d5dee7;
    border-radius: 5px;
    color: #0f3f3a;
    font-family: "Cascadia Code", Consolas, "Courier New", monospace;
    font-size: 0.92em;
}

pre,
pre.hljs {
    margin: 22px 0 32px;
    padding: 20px 22px;
    overflow-x: auto;
    background: var(--code-bg) !important;
    border-radius: 8px;
    box-shadow: inset 0 0 0 1px rgba(255, 255, 255, 0.08);
}

pre code,
pre code.hljs,
.hljs {
    padding: 0;
    background: transparent !important;
    border: 0;
    color: var(--code-text) !important;
    font-size: 0.94rem;
}

.hljs-keyword,
.hljs-built_in,
.hljs-type,
.hljs-literal,
.hljs-symbol {
    color: #67e8f9 !important;
}

.hljs-string,
.hljs-title,
.hljs-name {
    color: #bbf7d0 !important;
}

.hljs-comment,
.hljs-quote {
    color: #94a3b8 !important;
}

img {
    max-width: 100%;
    border-radius: 8px;
}

.mermaid {
    margin: 24px 0 34px;
    padding: 24px;
    overflow-x: auto;
    background: #ffffff;
    border: 1px solid var(--line);
    border-radius: 8px;
}

.mermaid svg {
    display: block;
    max-width: 100%;
    height: auto;
    margin: 0 auto;
}

.mermaid .node rect,
.mermaid .node circle,
.mermaid .node ellipse,
.mermaid .node polygon,
.mermaid .node path {
    stroke: var(--line-strong) !important;
}

.mermaid .edgePath path {
    stroke: var(--accent) !important;
}

@media (max-width: 720px) {
    body {
        margin: 0;
        padding: 28px 20px;
        border: 0;
        border-radius: 0;
        box-shadow: none;
    }

    h1 {
        font-size: 1.75rem;
    }

    h2 {
        font-size: 1.32rem;
    }

    table {
        display: block;
        overflow-x: auto;
        white-space: nowrap;
    }
}

@media print {
    html {
        background: #ffffff;
    }

    body {
        max-width: none;
        margin: 0;
        padding: 20mm;
        border: 0;
        border-radius: 0;
        box-shadow: none;
        color: #111827;
    }

    h1,
    h2,
    h3 {
        break-after: avoid;
    }

    table,
    pre,
    blockquote {
        break-inside: avoid;
    }
}
